package be.schaubroeck.lpb.rkm.rekenmotor.factory;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst.DoeSleutelTussenkomst;
import be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst.DoeTussenkomst;
import be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst.GenereerNeutraliserendeSleutelTussenkomst;
import be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst.GenereerNeutraliserendeTussenkomst;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import com.google.common.collect.ImmutableSet;
import org.apache.commons.chain.Command;
import org.apache.commons.chain.impl.ChainBase;

import java.util.Set;

public class NeutraliseerChainFactory extends RekenChainFactoryImp {

    public NeutraliseerChainFactory(ConstantManager constantManager, NlpGlobalService globalService) {
        super(constantManager, globalService);
    }

    public NeutraliseerChainFactory(Admin admin, NlpGlobalService globalService) {
        super(admin, globalService);
    }

    public static class NeutraliserendTussenkomstChain extends ChainBase {

        public NeutraliserendTussenkomstChain(NlpGlobalService globalService, Set<MoneyKey> bedragTypes) {
            super();
            addCommand(new DoeTussenkomst(bedragTypes));
            addCommand(new GenereerNeutraliserendeTussenkomst(globalService, bedragTypes));
            addCommand(new DoeTussenkomst(bedragTypes));
        }

        public NeutraliserendTussenkomstChain(NlpGlobalService globalService) {
            super();
            addCommand(new DoeTussenkomst());
            addCommand(new GenereerNeutraliserendeTussenkomst(globalService));
            addCommand(new DoeTussenkomst());
        }
    }

    public static class NeutraliserendSleutelTussenkomstChain extends ChainBase {

        public NeutraliserendSleutelTussenkomstChain() {
            this(ImmutableSet.of());
        }

        public NeutraliserendSleutelTussenkomstChain(Set<RekenBedragType> rekenBedragTypes) {
            super();
            addCommand(new DoeSleutelTussenkomst());
            addCommand(new GenereerNeutraliserendeSleutelTussenkomst(rekenBedragTypes));
            addCommand(new DoeSleutelTussenkomst());
        }

    }

    @Override
    protected Command getManueleTussenkomstCommand(Set<MoneyKey> bedragTypes, RekenFase rekenFase) {
        return new NeutraliserendTussenkomstChain(globalService, bedragTypes);
    }

    @Override
    protected Command getManueleTussenkomstPassiefCommand() {
        return new NeutraliserendTussenkomstChain(globalService);
    }

    @Override
    protected Command getSleutelTussenkomstCommand() {
        return new NeutraliserendSleutelTussenkomstChain();
    }

}
